    event LinkrPulled(address indexed addr, bytes32 indexed pubkey);

    // Secp256k1 curve constants
    uint256 private constant CURVE_ORDER = 0xFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFEBAAEDCE6AF48A03BBFD25E8CD0364141;
